class Solution:
    def delNodes(self, root, to_delete):
        ds = set(to_delete)
        roots = []
        # collect nodes top-down: BFS, marking which survive and who their parent is
        if root is None:
            return []
        # First, build parent links and prune deleted nodes bottom-up.
        def survives(node):
            if node is None:
                return None
            node.left = survives(node.left)
            node.right = survives(node.right)
            if node.val in ds:
                if node.left is not None:
                    roots.append(node.left)
                if node.right is not None:
                    roots.append(node.right)
                return None
            return node
        kept = survives(root)
        if kept is not None:
            roots.append(kept)
        roots.sort(key=lambda nd: nd.val)
        return roots

